//! E2e tests for category: static_files

use spikard::{App, RequestContext};

#[tokio::test]
async fn test_static_file_server_returns_text_file() {
    // Tests serving a plain text file with Cache-Control headers.
    let expected_body = r#""Hello from static storage""#.to_string();
    let mut app = spikard::App::new();
    app.route(
        spikard::get("/public/hello.txt"),
        move |_ctx: spikard::RequestContext| {
            let body = expected_body.clone();
            async move {
                Ok(axum::http::Response::builder()
                    .status(200u16)
                    .header("content-type", "application/json")
                    .body(axum::body::Body::from(body))
                    .unwrap())
            }
        },
    )
    .unwrap();
    let router = app.into_router().unwrap();
    let server = axum_test::TestServer::new(router);
    let response = server.get("/public/hello.txt").await;
    assert_eq!(response.status_code().as_u16(), 200u16);
}
